var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"20년 전, 관리 실패의 여파로 발생한 대균열은 프론트 베이의 모든 것을 집어삼켰단다.","JPN":"20年前、管理失敗の影響で発生した大亀裂は、フロントベイのすべてを飲み込んだわ。","ENG":"Twenty years ago, the aftermath of the Administration Failure unleashed a Grand Dimension Crevice that swallowed everything in Front Bay.","TWN":"20年前，因管理失誤引發的大峽谷吞噬了整個前灣。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리와 우리들은 그 재해 속에서 가까스로 살아남은 생존자들이었지.","JPN":"エイバリーと私たちは、あの災害からなんとか生き延びた者同士だった。","ENG":"Avery and the rest of us were the barely surviving remnants of that disaster.","TWN":"艾維利和我們，是那場災難中的倖存者。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"사람들은 살기 위해 서로의 것을 빼앗고, 죽이며 살아남았어.","JPN":"人々は生きるために奪い合い、殺し合った。","ENG":"People stole and killed each other just to live.","TWN":"人們為了生存互相掠奪、殺戮。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"빼앗기지 않기 위해, 죽지 않기 위해 모여든 사람들은 어느새 하나의 집단이 되었지.","JPN":"奪われないために、殺されないために、力を合わせた人々はやがて1つの集団になっていった。","ENG":"To avoid being robbed and to avoid dying, those who gathered together eventually became a single group.","TWN":"為了不被掠奪、為了求生，聚集的人們慢慢形成了一個群體。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그것이 에이버리 해적단의 시작이었단다.","JPN":"それがエイバリー海賊団の始まりだったわ。","ENG":"That was the beginning of the Avery Pirates.","TWN":"那就是艾維利海盜團的起源。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"결국 침식체로 인해 고향이 파괴된 우리는 바다로 나왔어.","JPN":"結局、侵食体によって故郷を破壊された私たちは海に出るしかなかった。","ENG":"In the end, with our homeland destroyed by C.O.s, we fled to sea.","TWN":"最終我們的家園被侵蝕體毀了，迫使我們踏上大海。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"살아남기 위해서.","JPN":"生きるために。","ENG":"Just to survive.","TWN":"為了生存。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"정처 없이 바다를 떠돌다 어느 섬에 도착해 본거지로 삼았지.","JPN":"あてもなく海を漂い、とある島に着いた私たちはその島を拠点にしたわ。","ENG":"We drifted without destination until we reached an island and made it our base.","TWN":"我們漂泊無依，直到找到一座島嶼作為落腳點。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이유는 무척이나 단순했단다.","JPN":"理由はとてもシンプルだった。","ENG":"The reason was simple.","TWN":"選擇那裡的理由很簡單。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그곳의 일출이 기가 막혔거든.","JPN":"そこの日の出が絶景だったのよ。","ENG":"The sunrise there was breathtaking.","TWN":"那裡的日出太美了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L21_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리는 그곳의 풍경을 모두가 보기를 바랐어.","JPN":"エイバリーはそこの景色をみんなに見てほしいと願ったわ。","ENG":"Avery wanted everyone to see that sight.","TWN":"艾維利希望每個人都能看到這片風景。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이걸 보고 감동한 사람들이 조금이라도 힘을 내지 않을까 생각했거든. ","JPN":"それを見て感動した人々が、少しでも元気を出せるんじゃないかって。 ","ENG":"He thought that maybe it would give people the strength to keep going.","TWN":"哪怕只是一點點，希望因此被感動的人們能振作起來。 "},"stage":{"bg":"SUMMER_CLIFF","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리는 바다를 모험하며 얻은 경험을 바탕으로 침식체를 사냥하고, 아티팩트를 가져와 사람들에게 나눠줬지.","JPN":"彼は海を冒険しながら得た経験をもとに、侵食体を狩り、アーティファクトを持ってきて、人々に分け与えたの。","ENG":"Avery hunted the C.O.s on the sea using what he learned from his adventures and shared the Artifacts he brought back.","TWN":"艾維利憑藉海上冒險的經驗狩獵侵蝕體、取得神器並分給人們。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"사람들을 약탈하던 사람들은 에이버리가 가져온 아티팩트를 보곤 바다로 나가기 시작했어.","JPN":"略奪を繰り返していた人々は、彼が持ってきたアーティファクトを見て海に出るようになった。","ENG":"The people who had lived by raiding others saw Avery's Artifacts and began heading out to sea.","TWN":"曾經掠奪他人的人看到艾維利帶回的神器，也開始展開海上之路。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그것이 프론트 베이에 해적이 생겨난 이유란다.","JPN":"それが、フロントベイに海賊が生まれた理由なのよ。","ENG":"That's why pirates were born in Front Bay.","TWN":"這就是為什麼前灣會出現海盜的原因。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그렇게 육지의 사람들은 서서히 질서를 되찾았단다.","JPN":"そうやって陸地は徐々に秩序を取り戻していったわ。","ENG":"And slowly, the people on land regained order.","TWN":"陸地上的人們逐漸找回秩序。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHILD"},{"id":"L32_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"내일을 꿈꾸길 포기한 사람들은 다시 오늘의 별을 바라보며 잠들 수 있게 되었지.","JPN":"明日を夢見ることを諦めていた人々は、再び今日の星を見上げて眠れるようになった。","ENG":"Those who had given up dreaming of tomorrow were once again able to sleep while looking up at the stars.","TWN":"放棄夢想明天的人，也能重新仰望今夜的星空入眠。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"하지만 그런 우리도 피할 수 없는 시간이 찾아왔어.","JPN":"でも、そんな私たちにも避けられない瞬間がやってきたの。","ENG":"But even we couldn't escape the passage of time.","TWN":"然而我們無法逃避的考驗也找上門了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"검은 범람의 발생이었습니다.","JPN":"黒い氾濫が発生したのです。","ENG":"The Black Flood.","TWN":"黑色洪災再次爆發。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L38_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"당시 사람들은 바다에서 엄청난 빛기둥이 솟아오른 것은 목격했지만…….","JPN":"当時、人々は海から巨大な光の柱が立つところは目撃したものの……","ENG":"Witnesses saw a massive pillar of light shoot up from the sea...","TWN":"當時人們看到巨大的光柱自海面升起……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그 빛기둥 속에서 무엇이 기어 나왔는지는 확인하지 못했으니까요.","JPN":"その光の柱から何が出てきたかは確認できませんでした。","ENG":"But no one saw what crawled out of that pillar of light.","TWN":"卻無法確認從光柱爬出的東西是什麼。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"무한 증식형 4종 침식체, 식별명 크라켄은 대균열 속에서 유체 형태로 바다에 부상했습니다.","JPN":"無限増殖型第4種侵食体、識別名クラーケンは大亀裂の中から幼体の形で海に浮上しました。","ENG":"The endlessly multiplying Category 4 C.O., designated Kraken, surfaced from the Grand Dimension Crevice in a larva form.","TWN":"無限增殖型4類侵蝕體，識別名「克拉肯」。以流體形態自大峽谷浮出海面。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"바다의 모든 것을 닥치는 대로 집어삼킨 녀석은… 어느새 재해를 일으킬 정도로 거대해졌죠.","JPN":"海のすべてを手当たり次第貪り尽くしたそれは……やがて災害を引き起こすほど巨大になっていきました。","ENG":"It devoured everything in the ocean... and grew into a disaster-class monster.","TWN":"吞噬大海一切的它……很快變大到足以引發災難的規模。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"하늘에서 뚝 떨어진 거대한 UFO.","JPN":"空から落ちてきた1隻の巨大なUFO。","ENG":"A giant UFO falling from the sky.","TWN":"天上掉下的飛船，"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그 당시엔 그렇게 생각했지만, 지금은 로스트 쉽이라 부르는 함선…….","JPN":"当時はそう思ってたけど……今はロストシップと呼ばれている艦船……","ENG":"That's what we thought back then, but now we call it the Lost Ship–","TWN":"當時我們以為是巨型UFO，但那時我們與現在被稱為失落艦船……"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"인빈서블과의 첫 만남이었단다.","JPN":"インビンシブルとの出会いもその時だったわね。","ENG":"It was our first encounter with the Invincible.","TWN":"無敵號的第一次邂逅。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그때, 에이버리가 이 모든 일이 외계인의 비밀 실험 때문이라고 소리를 질렀지.","JPN":"あの時、エイバリーがすべては宇宙人の秘密実験のせいだと声を上げたの。","ENG":"At the time, Avery shouted that the whole thing had to be some secret alien experiment.","TWN":"那時艾維利大喊這一切都是外星人的秘密實驗。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"크라켄이 그 소리에 자극받은 건지는 모르겠다만, 우리에게 인빈서블을 집어 던졌고…….","JPN":"その音に刺激されたのか、クラーケンは私たちにインビンシブルを投げつけ……","ENG":"Maybe Kraken reacted to that shouting because it threw the Invincible at us...","TWN":"不知道克拉肯是否因此受到刺激，它把無敵號扔向我們……"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그게 우리에게 있어서 절호의 기회가 되었지.","JPN":"それが私たちにとっての絶好のチャンスになったわ。","ENG":"And that became our chance.","TWN":"那對我們來說是千載難逢的機會。"},"stage":{"bg":"MAINSTREAM_000006","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리는 <color=#ffd34c>해적은 모험의 연속</color>이라고 말하며 겁도 없이 함선 안으로 들어갔단다.","JPN":"エイバリーは<color=#ffd34c>海賊は冒険の連続</color>だと言って、なんと大胆にも艦船の中に入っていったの。","ENG":"Avery said, <color=#ffd34c>\\"A pirate's life is endless adventure,\\"</color> and strode right into the ship without hesitation.","TWN":"艾維利說<color=#ffd34c>海盜就是冒險的延續</color>，毫無畏懼衝進艦船。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"함선 내부는 외계인이 실험 시설이 펼쳐져 있을 거란 우리의 기대와는 달리 처참했지.","JPN":"艦船の内部は、宇宙人の実験施設があるだろうという私たちの期待とは全く違って、凄惨な状況だった。","ENG":"But inside the ship, instead of some alien test facility we expected, was pure carnage.","TWN":"艦船內完全跟我們預想的外星實驗設施不同，而是慘不忍睹。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"잔인하게 훼손된 승무원들의 시체.","JPN":"残酷に傷つけられた乗組員たちの死体。","ENG":"Brutally mutilated crew.","TWN":"被殘忍破壞的船員屍體、"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"변이한 침식체.","JPN":"変異した侵食体。","ENG":"Mutated C.O.s.","TWN":"變異的侵蝕體、"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"알아들을 수 없는 말을 하며 공격하는 기계 병기들.","JPN":"理解できない言葉を発しながら攻撃してくる機械兵器の数々。","ENG":"Machines speaking nonsense as they attacked us.","TWN":"口中說著聽不懂的語言並攻擊的機械兵器。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리가 앞장서지 않았다면 우리도 검은 범람이고 뭐고 겁에 질려 도망치기 바빴을 거란다.","JPN":"エイバリーが先頭に立ってくれていなかったら、私たちも黒い氾濫はそっちのけで恐怖のあまり逃げ出していたでしょうね。","ENG":"If Avery hadn't led the way, we would've run in terror before dealing with the Black Flood or anything else.","TWN":"如果艾維利不帶頭，我們可能早就被黑色洪災嚇到逃跑了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"선장이 목숨 걸고 나아가준 덕택에, 우리는 다치는 사람은 있어도 죽는 사람은 없이 함교에 도달했지.","JPN":"船長が命懸けで前に進んでくれたおかげで、多少の負傷者はあれど誰も死ぬことなく艦橋にたどり着けたの。","ENG":"Because he risked his life to move forward, we reached the bridge with injuries without losing anyone.","TWN":"多虧船長拼命衝鋒。我們雖有人受傷，卻沒有人死亡，順利抵達艦橋。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그곳까지 도달하는 데에도 많은 어려움이 있었겠죠.","JPN":"そこにたどり着くまでにも、多くの困難があったと思います。","ENG":"It must've been a brutal climb to get that far.","TWN":"當然途中也遇到無數困難。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"썩 유쾌한 기억은 아니었다고만 말해두마.","JPN":"あまり愉快な記憶ではないとだけ言っておくわ。","ENG":"I'll just say it wasn't a pleasant memory.","TWN":"這稱不上是愉快的回憶。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"인빈서블은 이미 한차례 크라켄과의 전투로 인해 많은 곳이 망가진 상태였어.","JPN":"インビンシブルはすでに一度クラーケンとの戦闘があったらしく、かなりあちこちが壊れている状態だった。","ENG":"The Invincible was already heavily damaged from a previous battle with Kraken.","TWN":"無敵號在與克拉肯的戰鬥後，有許多地方已經損毀。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아마 급하게 현실로 부상하는 과정에서 크라켄에게 붙잡힌 모양인 것 같았지.","JPN":"おそらく、急いで現実に浮上する過程でクラーケンに捕まってしまったんでしょう。","ENG":"It looked like Kraken had grabbed the ship as it rushed to surface into reality.","TWN":"可能是在急速浮上現實的過程中被克拉肯抓住。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그들은 어떻게든 살아남기 위해 맞서 싸웠지만…….","JPN":"インビンシブルの乗組員たちは、なんとか生き残るために立ち向かったけれど……","ENG":"They fought desperately to survive...","TWN":"他們雖然為了活下去奮力抵抗……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이미 기울어진 전세를 뒤집는 건 힘들었던 것 같구나.","JPN":"劣勢を覆すことは叶わなかったのね。","ENG":"But it was impossible to overturn the already hopeless situation.","TWN":"卻難以改變已經逆轉的戰局。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"하지만 그곳의 선장은 퍽 훌륭한 자였다는 건 기억하고 있단다.","JPN":"でも、あの船の船長はなかなか立派な人だったってことは覚えているわ。","ENG":"But I remember clearly that the captain of that ship was remarkable.","TWN":"不過我記得那裡的船長非常出色。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"죽는 그 순간까지 손에서 핸들과 열쇠를 놓지 않았으니.","JPN":"息絶えるその瞬間まで、ハンドルと鍵を握っていたの。","ENG":"Even in death, he never let go of the helm or the key.","TWN":"直到生命最後一刻，都沒有放開方向盤和鑰匙。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"에이버리. 이곳은 너무 위험해.","JPN":"エイバリー。ここは危険すぎる。","ENG":"Avery. It's too dangerous here.","TWN":"艾維利，這裡太危險了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"이 우주선인지 뭔지 모를 것이 우릴 구해줄 수단이라고 하더라도…….","JPN":"この宇宙船だか何だか分からないものが私たちを救ってくれる手段だとしても……","ENG":"Even if this spaceship or whatever it is could save us...","TWN":"就算那不知道是飛船還是什麼的東西能救我們……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"하지만 사람이 위험하다는데 꼬리를 말고 도망가자는 거야?!","JPN":"フロントベイのみんなが危険に晒されているのに尻尾を巻いて逃げようっていうのか！？","ENG":"But someone's in danger, and you're telling me we should tuck our tails and run?!","TWN":"可是明明有人遇到危險，你卻要我夾著尾巴逃走？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"지푸라기라도 잡는 심정으로 우리는 여기에 온 거잖아.","JPN":"私たちは藁にもすがる思いでここに来たんじゃないか。","ENG":"We came here clinging to even the slightest hope, didn't we?!","TWN":"我們是抱著抓住最後一根稻草的心情來到這裡的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"다들 죽거나 다치는 것쯤은 각오하고 왔어!","JPN":"死ぬことや怪我することくらい、覚悟の上だ！","ENG":"We knew people might die or get hurt coming in!","TWN":"大家都有覺悟可能會死、會受傷！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"현실적으로 생각해 보자는 거란다. 보니.","JPN":"現実的に考えようと言っているのよ、ボニー。","ENG":"Try to think realistically, Bonny.","TWN":"妳冷靜想想，寶妮。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"에이버리나, 너나 사람을 구해야겠다는 마음은 이해하지만, 이건 너무 위험해.","JPN":"エイバリーもあなたも、人を救いたい気持ちはわかるけど、これは危険すぎる。","ENG":"I know you and Avery both want to save people, but this is far too dangerous.","TWN":"艾維利，你、還有我，想救人的心情我懂，但現在太危險了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"이미 이곳까지 오는 길에도 많은 선원들이 다쳤잖니?","JPN":"ここに来るまでもたくさんの船員が怪我をしたじゃない。","ENG":"Many of our crew were injured just getting here.","TWN":"光是到這裡的路上，就已有不少船員受傷。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"우리마저 이곳에서 모두 죽으면, 그때 육지의 사람들은 누가 지켜줘?","JPN":"私たちまでここ全滅してしまったら、陸の人たちを誰が守るの？","ENG":"If we all die in this place, who will protect the people on land?","TWN":"如果我們也全死在這裡，那誰來保護陸地上的人？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그렇기 때문에 물러설 수 없는 거야, 리드.","JPN":"だからこそ引き下がれないんだ、リード。","ENG":"And that's exactly why we can't retreat, Read.","TWN":"正因為如此我們才不能退縮，里德。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"우리는 저 희생을 딛고 어떻게든 검은 범람을 이겨낼 방법을 찾아내야만 해.","JPN":"私たちは彼らの犠牲を乗り越えて、どうにかして黒い氾濫を克服する方法を見つけなければならない。","ENG":"We have to stand on the sacrifices already made and find a way to overcome the Black Flood.","TWN":"我們得踏過那些犧牲的人，無論如何都要找出戰勝黑色洪災的方法。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"만약 이 모험의 끝에서 검은 범람을 끝내는 대신 내 목숨이 필요하다고 한다면…….","JPN":"もしこの冒険の果てで、黒い氾濫を終わらせるために私の命が必要であるのなら……","ENG":"If, at the end of this journey, ending the Black Flood requires my life...","TWN":"如果這趟冒險的終點，是要用我的性命交換終結洪災……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"나는 기꺼이 내 목을 내어줄 거다.","JPN":"喜んで自分自身を差し出してやる。","ENG":"I'll gladly give my life for it.","TWN":"我會毫不猶豫獻出自己的生命。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"하지만 선원들이 희생할 필요는 없지.","JPN":"だが、船員たちが犠牲になる必要はない。","ENG":"But the crew doesn't need to die.","TWN":"但不該再有船員犧牲。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"보니, 리드. 너희는 이제 그만 돌아가.","JPN":"ボニー、リード。お前たちはもう戻れ。","ENG":"Bonny, Read. You two should head back.","TWN":"寶妮、里德，你們現在就回去吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"지금쯤 로조도 정신을 차렸을 테니 데리고 나가고.","JPN":"そろそろロッゾも目覚める頃だろうから、連れて行け。","ENG":"Rojo should be conscious by now. Take him with you.","TWN":"羅梭現在應該也醒了，帶他回去。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"잠깐, 선장!","JPN":"ちょっと、船長！","ENG":"Wait, Captain!","TWN":"等等，船長！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"그게 무슨 소리야?!","JPN":"どういうことだよ！？","ENG":"What are you talking about?!","TWN":"你這是什麼意思？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"이런 곳에 선장만 두고 나갈 수는 없다고.","JPN":"こんなところに、船長だけ1人置いていけってことか！","ENG":"We can't just leave you behind in a place like this!","TWN":"我們怎麼可能把你丟在這種地方！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"보니.","JPN":"ボニー。","ENG":"Bonny.","TWN":"寶妮。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"너에겐 태어난 지 얼마 안 된 딸이 있지 않나?","JPN":"お前には生まれたばかりの娘がいるだろう？","ENG":"You have a newborn daughter, don't you?","TWN":"妳不是有個剛出生不久的女兒嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"검은 범람 때문에 아버지를 일찍 잃은 그 아이에게 적어도… 어머니라는 존재는 있어야지.","JPN":"黒い氾濫のせいで早くに父親を亡くしたその子には、少なくとも……母親という存在が必要だ。","ENG":"Because of the Black Flood, she already lost her father too early... at least she should still have a mother.","TWN":"那孩子早就因為黑色洪災失去父親，至少……她不能再失去母親。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"그럼 처음부터 날 배에 태우지 말았어야지!","JPN":"だったら最初から私を船に乗せなきゃよかったんだ！","ENG":"Then you shouldn't have let me on the ship in the first place!","TWN":"那你當初就不該讓我上船啊！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"선장은 배는 버려도 선원은 버리지 않는다.","JPN":"船長は船は捨てても船員は捨てない。","ENG":"The captain may abandon the ship, but doesn't abandon the crew.","TWN":"船長可以捨棄船，但絕不會丟下船員。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"당신이 입이 닳도록 했던 그 말, 당신은 여태 훌륭하게 지켜왔잖아.","JPN":"口酸っぱく言ってきたこの言葉、あんたは今まで立派に守ってきたじゃないか。","ENG":"You've kept that promise perfectly all this time.","TWN":"你一直堅守著那句講破嘴巴的話。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"우리는 여태껏 당신의 등을 바라보며 바다를 헤쳐 나갔어.","JPN":"私たちは今まであんたの背中を見つめながら海を進んできたんだ。","ENG":"We followed your back and crossed these seas because we believed in you.","TWN":"我們一直都是看著你的背影，一起闖過這片海洋。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"근데 이런 순간마저도 당신이 우릴 위해 희생하겠다고 하는 걸…….","JPN":"なのに、こんな時まで、あんたが私たちのために犠牲になるっていうのを……","ENG":"But now, in this moment, you're the one saying you'll sacrifice yourself for us...","TWN":"你連這種時刻都要為我們犧牲……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"어떻게 받아들일 수 있겠어?","JPN":"受け入れられるわけないだろう？","ENG":"How are we supposed to accept that?","TWN":"要我們怎麼接受？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"보니…….","JPN":"ボニー……","ENG":"Bonny...","TWN":"寶妮……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"선장. 우리는 한 팀이야.","JPN":"船長。私たちはチームなんだ。","ENG":"Captain. We're a team.","TWN":"船長，我們是一個團隊。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"선장이 선원을 버리지 않는 것처럼, 선원도 선장을 버리지 않는 게 해적의 룰이라고.","JPN":"船長が船員を捨てないように、船員も船長を捨てないのが海賊のルールなんだよ。","ENG":"Just like a captain doesn't abandon the crew, the crew doesn't abandon the captain. That's the pirate's rule.","TWN":"就像船長不拋棄船員一樣，船員也不會丟下船長，這就是海盜的規矩。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"물러나야 한다는 입장은 찬성이란다.","JPN":"引き下がるべきだという意見には賛成よ。","ENG":"I still think we should retreat.","TWN":"我也同意要撤退。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"하지만 보니의 말대로, 돌아가야 하는 건 모두여야 해.","JPN":"でもボニーの言うとおり、戻るときはみんな一緒じゃないとダメ。","ENG":"But like Bonny said, if we withdraw, we all withdraw together.","TWN":"但就像安說的，要撤退就大家一起撤退。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"선장. 선장의 목숨은 당신 하나만의 것이 아니야.","JPN":"船長。船長の命はあなただけのものではないの。","ENG":"Captain. Your life doesn't belong only to you.","TWN":"船長，你的性命不是只屬於你的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"우리 해적단의, 아니…….","JPN":"私たち海賊団の、いいえ……","ENG":"Every member of our crew– no...","TWN":"我們海盜團……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"프론트 베이의 모두가 당신에게 의지하고 있다고.","JPN":"フロントベイのみんながあなたを頼りにしてる。","ENG":"All of Front Bay depends on you.","TWN":"不，整個前灣的人都倚靠你。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_ADMIN_QM","text":{"KOREA":"저기…….","JPN":"あの……","ENG":"Um...","TWN":"那個……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_ADMIN_QM","text":{"KOREA":"다들 이야기는 좀 끝나셨나요?","JPN":"皆さん、お話は終わりましたか？","ENG":"Are you all done talking?","TWN":"你們討論結束了嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"누구지?","JPN":"誰だ？","ENG":"Who are you?","TWN":"是誰？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"아직 살아 있는 생존자인가?!","JPN":"まだ生存者がいたのか！？","ENG":"A survivor?!","TWN":"是還活著的生還者？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"저, 전… 관리국 오퍼레이팅 시스템, 모네카에요.","JPN":"わ、私は……管理局のオペレーティングシステム、モネカです。","ENG":"I-I'm... Moneka, the Administration's operating system.","TWN":"我、我是管理局的標準作業系統莫奈卡。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"본래 이 함선은 일반인에게 보이지 않도록 인지 왜곡 필터를 적용하고 있었을 텐데…….","JPN":"本来この艦船は一般人には見えないように認識歪曲フィルターを適用していたはずですが……","ENG":"This ship should have an awareness distortion filter that hides it from civilians...","TWN":"這艘艦船為了不讓普通人看到，本來應該安裝了認知扭曲濾鏡……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"오퍼레이팅 시스템? 모네카……?","JPN":"オペレーティングシステム？　モネカ……？","ENG":"Operating system? Moneka...?","TWN":"標準作業系統？莫奈卡……？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그게 도대체 뭐지?","JPN":"何だそれは？","ENG":"What in the world is that?","TWN":"到底是什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"무슨 일이 있었던 거죠?","JPN":"何があったのでしょうか？","ENG":"What exactly happened here?","TWN":"發生什麼事了？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"인지 왜곡… 필터? 함선?","JPN":"認識歪曲……フィルター？　艦船？","ENG":"Awareness distortion... filters? A ship?","TWN":"認知扭曲……濾鏡？艦船？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"무슨 말을 하는지 모르겠군.","JPN":"何のことだかさっぱりだな。","ENG":"I don't know what you're talking about.","TWN":"我聽不懂你在說什麼。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그럼 당신 말대로라면, 이게 우주선이나 외계인의 소행이 아니라는 거야?","JPN":"では君の言うとおりだとすると、これは宇宙船や宇宙人の仕業ではないということか？","ENG":"So by your words, this isn't the work of aliens or a spaceship?","TWN":"照你這麼說，這就不是宇宙船或外星人所為了？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"다, 당연하죠.","JPN":"あ、当たり前です！","ENG":"O-of course not!","TWN":"當、當然不是。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"저도 외계인이 있으면 좀 만나보고 싶은데요?","JPN":"そんなものがいたら、私も会ってみたいくらいです。","ENG":"Though I wouldn't mind meeting aliens if they existed.","TWN":"我也很想見見外星人耶？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"선장. 지금 서로 명함 교환이나 하자고 여기 온 건 아니잖아.","JPN":"船長。今は名刺交換のためにここに来てるわけじゃないだろう？","ENG":"Captain. We're not here to exchange business cards.","TWN":"船長，我們來這裡不是為了交換名片吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"모네카. 우리는 지금 우리 고향을 덮친 검은 범람을 끝내기 위해 위험을 무릅쓰고 여기 왔어.","JPN":"モネカ。私たちは今、故郷を襲った黒い氾濫を終わらせるために危険を冒してまでここに来てる。","ENG":"Moneka. We came risking our lives to end the Black Flood ravaging our home.","TWN":"莫奈卡。我們冒著危險來到這裡，就是為了終結侵襲我們故鄉的黑色洪災。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"너와 네 선원들에게는 못 할 말이지만, 검은 범람을… 크라켄을 이길 수 있는 방법이 필요해.","JPN":"あんたとあんたの船員には悪いが、黒い氾濫に……クラーケンに勝てる方法が必要なんだ。","ENG":"This isn't something your crew would want to hear, but we need a way to defeat the Black Flood... to defeat Kraken.","TWN":"或許不能對你和你的船員這麼說……但我們需要能戰勝黑色洪災、戰勝克拉肯的方法。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"이… 수많은 희생을 헛되이 하지 않기 위해서라도.","JPN":"この……たくさんの犠牲を無駄にしないためにも。","ENG":"We can't let... all these sacrifices be for nothing.","TWN":"為了不讓那無數的犧牲白費。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이 함선, <color=#ffd34c>글레입니르</color>는 관리국 표준 차원 함선이에요.","JPN":"この艦船、<color=#ffd34c>グレイプニル</color>は管理局標準次元艦船です。","ENG":"This ship, <color=#ffd34c>Gleipnir</color>, is a standard Administration dimensional ship.","TWN":"這艘艦艇，<color=#ffd34c>格萊伊尼勒</color>，是管理局標準的次元艦艇。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"일반인들에게 설명하기는 좀 어렵지만… 이 함선은 저런 침식체들을 상대하기 위해 건조되었습니다.","JPN":"一般の人に説明するのは少々難しいですが……この艦船は、ああいった侵食体を相手にするために建造されました。","ENG":"It's a bit hard to explain to civilians... but this ship was built to fight C.O.s like those.","TWN":"雖然難以向普通人說明……但它是專為對付侵蝕體打造的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"지금은 가동이 정지되었지만, 여러분이 도와준다면…….","JPN":"今は稼働を停止していますが……皆さんが手を貸してくださるなら……","ENG":"It's inactive right now, but if you help me...","TWN":"雖然目前已停止運轉，但若你們幫忙……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"무한 증식형 4종 침식체, 식별명 크라켄을 물러나게 할 수 있을 거예요.","JPN":"無限増殖型第4種侵食体、識別名クラーケンを退かせることができるでしょう。","ENG":"We can force back the endlessly multiplying Category 4 C.O., Kraken.","TWN":"可以逼退無限增殖型4類侵蝕體，識別名「克拉肯」。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"침식체… 그게 저 괴물들을 지칭하는 이름인가…….","JPN":"侵食体……それがあの化け物たちの名前なのか……","ENG":"C.O.s... So that's what you call those monsters...","TWN":"侵蝕體……那就是那些怪物的名字嗎……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"좋아. 방법을 알려줘.","JPN":"いいだろう。方法を教えてくれ。","ENG":"All right. Tell me what to do.","TWN":"好，告訴我方法。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"이 배를 지키기 위해 희생된 사람들을 위해서라도, 내가 반드시 가동할 테니까.","JPN":"この船を守るために犠牲になった人々のためにも、私が必ず稼働させる。","ENG":"For the sake of everyone who died protecting this ship... I'll get it running.","TWN":"我一定會為了那些守護這艘船而犧牲的人成功啟動它。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"배를 가동하는 과정은 생략하도록 하마.","JPN":"船の稼働に至る過程については省略するわ。","ENG":"I'll skip over the activation process.","TWN":"我就省略啟動船的過程。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"전선을 다시 연결하고, 피 웅덩이 속에서 떨어진 부품을 찾는 것의 연속이었으니.","JPN":"電線をつなぎ直し、血溜まりの中から部品を探すことの連続だったしね。","ENG":"It was just reconnecting wires and fishing parts out of puddles of blood.","TWN":"我們持續重新接線、在血泊裡找零件。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그리고 우여곡절 끝에… 관리국 기함, 글레입니르는 가동을 시작했지.","JPN":"そして紆余曲折を経て……管理局旗艦、グレイプニルは再び稼働した。","ENG":"But after countless setbacks... the Administration Flagship, Gleipnir, finally roared back to life.","TWN":"總之歷經曲折後……管理局的旗艦格萊伊尼勒終於開始運作。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"어, 엄밀히 말하면, 방금 하신 행위는 관리국 기술 유출 방지법에 반하는 행위에요.","JPN":"げ、厳密に言うと、今の行為は管理局の技術輸出防止法に反する行為です。","ENG":"Strictly speaking... what you just did violates the Administration's Technology Protection Act.","TWN":"嚴格說來，你剛才的行為已經違反管理局的技術外流防治法。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"관리국과 관련되지 않은 민간인에게 함부로 그 유산을 넘길 수 없으니까요.","JPN":"管理局と関係のない民間人に、勝手に遺産を引き渡すわけにはいかないので。","ENG":"We can't hand over our legacy to civilians outside the Administration.","TWN":"我們不能把管理局的遺產隨便交給普通平民。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"본래라면 기억 소거 조치를 취하고…….","JPN":"本来なら記憶消去措置をして……","ENG":"Normally, we'd proceed with memory erasure...","TWN":"照理來說應該要刪除你的記憶……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"민간인? 관리국 기술 유출 방지법?","JPN":"民間人？　管理局の技術輸出防止法？","ENG":"Civilians? Technology Protection Act?","TWN":"平民？技術外流防治法？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"착각하고 있군, 아가씨.","JPN":"何か勘違いしているな、お嬢さん。","ENG":"You're misunderstanding, miss.","TWN":"妳搞錯了，小姑娘。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"우린 땅을 지키기 위해 이곳에 온 해적이야.","JPN":"私たちは陸地を守るためにここに来た海賊だ。","ENG":"We're pirates who came here to protect our land.","TWN":"我們是為了守護這片土地才來到這裡的海盜。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"해적이 규칙이나 법 운운하는 걸 본 적 있나?","JPN":"ルールや法律に従う海賊がいると思うか？","ENG":"Since when do pirates care about rules or laws?","TWN":"妳有看過海盜會遵守什麼規則或法律嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"흥, 함선을 무단점거 한 주제에, 말은 잘 하는 군요.","JPN":"ふん、艦船を無断占拠したくせに、ぬけぬけとよくいいますね。","ENG":"Hmph. You've got a lot of nerve for someone illegally occupying a ship.","TWN":"哼，私自占據艦艇的人還把話說得這麼好聽。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"좋아요. 지금은 특수한 상황이니 특별히 예외 조항을 적용하도록 하죠.","JPN":"いいでしょう。今は特殊な状況ですから、特別に例外条項を適用します。","ENG":"Fine. It's a special situation, so I'll make an exception.","TWN":"好吧。現在是特殊情況，我就破例啟動特別條款。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"예외 조항……?","JPN":"例外条項……？","ENG":"An exception...?","TWN":"特別條款……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"우리에겐 공동의 적이 있어요.","JPN":"私たちには共通の敵がいます。","ENG":"We share a common enemy.","TWN":"現在我們有共同的敵人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그러니 글레입니르의 모든 권한을 임시로 당신들에게 인계하겠습니다.","JPN":"だからグレイプニルの全権限を、臨時であなたたちに引き渡します。","ENG":"So I will temporarily transfer full control of Gleipnir to all of you.","TWN":"所以我將把格萊伊尼勒的所有權限暫時轉交給你們。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"오퍼레이션 레디! 에너지 공급 활성화!","JPN":"オペレーションレディ！　エネルギー供給活性化！","ENG":"Operation ready! Power supply active!","TWN":"計劃待命！能源供應啟動！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"아직 함선 내부에 이터니움이 남아 있어서 다행이에요.","JPN":"まだ艦船内部にエタニウムが残っていてよかったです。","ENG":"Good thing the ship still had some Eternium left.","TWN":"幸好艦內還殘留一些永恆之金。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그럼 글레입니르… 발진합니다!","JPN":"では、グレイプニル……発進します！","ENG":"Gleipnir... taking off!","TWN":"那麼格萊伊尼勒……起航！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"아니, 항해사.","JPN":"いいや、航海士。","ENG":"No, navigator.","TWN":"不，航海士。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"오늘부터 배의 이름은 인빈서블이다.","JPN":"今日からこの船の名前はインビンシブルだ。","ENG":"From today on, this ship's name is Invincible.","TWN":"從今天起，這艘船叫無敵號。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네? 가, 갑자기요?","JPN":"え？　い、いきなりですか？","ENG":"Huh? J-just like that?","TWN":"什麼？這、這麼突然嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"후후, 해적에게 있어 배의 이름을 짓는 건 그 어느 때보다 중요한 순간이거든.","JPN":"ふふ。海賊にとって船に名前をつけるというのは、何よりも重要だからな。","ENG":"Fufu. Naming a ship is the most important thing to a pirate.","TWN":"呵呵。對海盜來說，替船命名可是最重要的時刻。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"우리는 누구에게도 꺾이지 않으니까.","JPN":"私たちは何者にも屈しない。","ENG":"We bow to no one.","TWN":"我們不會向任何人屈服。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그래서 인빈서블이야.","JPN":"だからインビンシブルだ。","ENG":"That's why it's the Invincible.","TWN":"所以叫無敵號。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"풋, 역시 제멋대로네요.","JPN":"ぷふっ、やっぱり自分勝手ですね。","ENG":"Pfft. Unbelievable.","TWN":"噗，果然還是那麼自我呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"그러니까 해적이지.","JPN":"それでこそ海賊だ。","ENG":"That's what makes us pirates.","TWN":"所以才是海盜啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"이 바다에서 가장 자유로운 존재라고.","JPN":"この海で最も自由な存在さ。","ENG":"The freest souls on the sea.","TWN":"是這片大海上最自由的存在。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"후후, 좋아요. 그럼 임시 선장의 뜻을 따르겠습니다.","JPN":"ふふ、わかりました。臨時船長の指示に従います。","ENG":"Fufu. Very well. I'll follow the interim captain's wishes.","TWN":"呵呵，好吧，那我就遵從臨時船長的命令。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_PRIDE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그럼, 인빈서블.","JPN":"では、インビンシブル。","ENG":"Then, Invincible.","TWN":"無敵號，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_PRIDE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"가동하겠습니다!","JPN":"稼働します！","ENG":"Engaging systems!","TWN":"開始運轉！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CITY_FRONTBAY_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"뒷이야기는 나도 알고 있어.","JPN":"その後の話はあたしも知ってる。","ENG":"I know the rest of the story.","TWN":"後面的事我也聽說了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"인빈서블과 함께 에이버리 해적단은 크라켄과 맞서 싸웠고, 크라켄과 함께 바닷속으로 사라졌다.","JPN":"インビンシブルと共にエイバリー海賊団はクラーケンに立ち向かい、クラーケンと共に海の底へ消えた。","ENG":"With Invincible at their side, the Avery Pirates fought Kraken... and vanished into the sea with it.","TWN":"無敵號與艾維利海盜團對抗深海巨獸克拉肯，最後與克拉肯一起沉入大海。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리는 자신의 희생으로 검은 범람을 몰아내고 자신의 기함, 인빈서블과 함께 바다를 지키고 있을 것이다.","JPN":"エイバリーは自分を犠牲に黒い氾濫を追い払い、自分の旗艦インビンシブルと共に今も海を守っている。","ENG":"Avery drove back the Black Flood with his own sacrifice and now protects the seas alongside his Flagship, Invincible.","TWN":"艾維利犧牲自己驅散黑色洪災，並與自己的旗艦無敵號一起守護著這片海域。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"수많은 해적이…….","JPN":"多くの海賊が……","ENG":"Countless pirates...","TWN":"無數海盜……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그의 지워지지 않는 모험담을 동경해 바다로 나오고 있다.","JPN":"消えることのない彼の冒険譚に憧れて、海へ向かう。","ENG":"Head out to sea, inspired by the legend he left behind.","TWN":"因為嚮往他那永不磨滅的冒險，才踏上航海旅程。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후훗, 어렸을 때의 기억을 잘 간직하고 있었구나, 키이라.","JPN":"ふふ、子どもの頃の記憶を忘れずにいてくれたのね。キーラ。","ENG":"Fufu, you held on to your childhood memories well, Kiera.","TWN":"呵呵，看來妳都有記住孩提時的記憶嘛，琪伊拉。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그, 그럼 아줌마.","JPN":"てことは、おばさん。","ENG":"Th-then, Auntie Mary...","TWN":"那、那麼阿姨，"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"엄마는…….","JPN":"お母さんは……","ENG":"My mom... Is she–","TWN":"我媽媽她……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"啊……！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"왜 갑자기 배가……?","JPN":"なんで急に船が……？","ENG":"Why is the ship suddenly rocking...?","TWN":"船怎麼突然……？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아무래도 우리에게 주어진 시간이 많이 없는 것 같구나.","JPN":"どうやら私たちに残された時間は、そう長くないみたいね。","ENG":"It seems the time given to us is running short.","TWN":"看來我們剩下的時間不多了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"탈리, 상황을 좀 봐줄 수 있겠니?","JPN":"タリー、状況を把握してくれる？","ENG":"Tallie, could you check what's happening?","TWN":"塔莉，妳能去確認一下狀況嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"네, 넵! 어머니!","JPN":"は、はい！　お母様！","ENG":"Y-yes! Mother!","TWN":"好、好！母親！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"서둘러 알아보겠습니다!","JPN":"早速調べてみます！","ENG":"I'll look into it right away!","TWN":"我馬上去！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"이, 이상한 걸 발견했습니다!","JPN":"へ、変なものを見つけました！","ENG":"I-I found something strange!","TWN":"我、我發現一些奇怪的東西！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"마하 섬 방향에서 정체불명의 빛기둥 관측!","JPN":"マッハ島方面から正体不明の光の柱を観測！","ENG":"A massive unidentified pillar of light coming from Macha Island!","TWN":"在瑪查島方向觀測到不明的光柱！"},"stage":{"bg":"OMEN_FRONTBAY_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저곳이 바로…….","JPN":"あそこは、たしか……","ENG":"That must be...","TWN":"那裡就是……"},"stage":{"bg":"OMEN_FRONTBAY_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래. 상처 입은 크라켄을 다시 움직이게 한 원흉이자…….","JPN":"ええ。手負いのクラーケンを再び動かした元凶であり……","ENG":"Yes. The very thing that reawakened the wounded Kraken...","TWN":"嗯，讓受傷的克拉肯再次行動的罪魁禍首……"},"stage":{"bg":"OMEN_FRONTBAY_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"어쩌면… 20년 전, 이 모든 재앙의 시발점이 된 곳.","JPN":"もしかしたら……20年前、このすべての災害の原点かもしれない場所。","ENG":"And perhaps... the place where this entire disaster began twenty years ago.","TWN":"或許是……20年前一切災厄的起點。"},"stage":{"bg":"OMEN_FRONTBAY_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"프론트 베이의 대균열이란다.","JPN":"フロントベイの大亀裂よ。","ENG":"The Grand Dimension Crevice of Front Bay.","TWN":"前灣的大峽谷。"},"stage":{"bg":"OMEN_FRONTBAY_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};